import {useRef,useState} from 'react';export default function LoginForm(){const[u,su]=useState('');const[p,sp]=useState('');const ref=useRef();const sub=e=>{e.preventDefault();if(!u||!p){alert('Fill all fields');return;}alert('Login Successful');su('');sp('');ref.current.focus();};return <div className='card p-3'><form onSubmit={sub}><h4>Login</h4><input ref={ref} value={u} onChange={e=>su(e.target.value)} className='form-control mt-2' placeholder='Username'/><input type='password' value={p} onChange={e=>sp(e.target.value)} className='form-control mt-2' placeholder='Password'/><button className='btn btn-success mt-3 w-100'>Login</button></form></div>}